"use strict";(globalThis.webpackChunkspark_study=globalThis.webpackChunkspark_study||[]).push([[8954],{6844(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"week-1-caching-vs-checkpointing","metadata":{"permalink":"/spark-study/blog/week-1-caching-vs-checkpointing","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-02-22-cache-checkpoint-kwon.md","source":"@site/blog/2026-02-22-cache-checkpoint-kwon.md","title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","description":"Spark \uc131\ub2a5 \ucd5c\uc801\ud654\uc758 \ud575\uc2ec\uc778 Caching(StorageLevel)\uacfc Checkpointing\uc758 \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uae4a\uc774 \uc788\uac8c \ube44\uad50\ud558\uace0, \uc2e4\ubb34 \uc801\uc6a9 \uae30\uc900\uc744 \uc815\ub9ac\ud55c\ub2e4.","date":"2026-02-22T00:00:00.000Z","tags":[{"inline":true,"label":"spark","permalink":"/spark-study/blog/tags/spark"},{"inline":true,"label":"scala","permalink":"/spark-study/blog/tags/scala"},{"inline":true,"label":"optimization","permalink":"/spark-study/blog/tags/optimization"},{"inline":true,"label":"caching","permalink":"/spark-study/blog/tags/caching"},{"inline":true,"label":"checkpointing","permalink":"/spark-study/blog/tags/checkpointing"}],"readingTime":3.59,"hasTruncateMarker":false,"authors":[{"name":"Kwon Younglin","title":"Data Engineer","url":"https://github.com/kwonyl14","imageURL":"https://github.com/kwonyl14.png","key":"kwonyl14","page":null}],"frontMatter":{"slug":"week-1-caching-vs-checkpointing","title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","authors":["kwonyl14"],"tags":["spark","scala","optimization","caching","checkpointing"],"description":"Spark \uc131\ub2a5 \ucd5c\uc801\ud654\uc758 \ud575\uc2ec\uc778 Caching(StorageLevel)\uacfc Checkpointing\uc758 \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\ub97c \uae4a\uc774 \uc788\uac8c \ube44\uad50\ud558\uace0, \uc2e4\ubb34 \uc801\uc6a9 \uae30\uc900\uc744 \uc815\ub9ac\ud55c\ub2e4."},"unlisted":false,"nextItem":{"title":"1\uc8fc\ucc28: Spark DataFrame OOM \ud14c\uc2a4\ud2b8 \ubc0f \ud658\uacbd \uc138\ud305","permalink":"/spark-study/blog/first-test"}},"content":"\uc2a4\ud30c\ud06c(Spark) \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc744 \uac1c\ubc1c\ud558\ub2e4 \ubcf4\uba74 Join\uc774\ub098 \uc815\ub82c(Sort) \uac19\uc740 \ubb34\uac70\uc6b4(Expensive) \uc5f0\uc0b0 \uacb0\uacfc\ub97c \uc5ec\ub7ec \ubc88 \uc7ac\uc0ac\uc6a9\ud574\uc57c \ud558\ub294 \uc0c1\ud669\uc774 \ubc18\ub4dc\uc2dc \ubc1c\uc0dd\ud55c\ub2e4. \uc774\ub54c \uc544\ubb34 \ucc98\ub9ac\ub3c4 \ud558\uc9c0 \uc54a\uc73c\uba74 \uc561\uc158(Action)\uc774 \ud638\ucd9c\ub420 \ub54c\ub9c8\ub2e4 \ub370\uc774\ud130\ub97c \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uc77d\uace0 \uacc4\uc0b0\ud558\ub294 \uc5c4\uccad\ub09c \ube44\ud6a8\uc728\uc774 \ubc1c\uc0dd\ud55c\ub2e4.\\n\\n\uc774 \ubb38\uc81c\ub97c \ud574\uacb0\ud558\ub294 \ub450 \uac00\uc9c0 \ud575\uc2ec \ubb34\uae30\uac00 \ubc14\ub85c **\uce90\uc2f1(Caching)** \uacfc **\uccb4\ud06c\ud3ec\uc778\ud305(Checkpointing)** \uc774\ub2e4. \ub450 \uae30\ubc95\uc740 \ube44\uc2b7\ud574 \ubcf4\uc774\uc9c0\ub9cc \ub0b4\ubd80 \ub3d9\uc791 \uc6d0\ub9ac\uc640 \ubaa9\uc801\uc774 \uc644\uc804\ud788 \ub2e4\ub974\ub2e4. \ucf54\ub4dc\ub97c \ud1b5\ud574 \uc774 \ub458\uc758 \ucc28\uc774\ub97c \ud655\uc778\ud55c\ub2e4.\\n\\n---\\n\\n## 1. Caching: \ube60\ub978 \uc7ac\uc0ac\uc6a9\uc744 \uc704\ud55c \uba54\ubaa8\ub9ac \ucd5c\uc801\ud654\\n\\n\uce90\uc2f1\uc740 \uacc4\uc0b0\uc774 \ub05d\ub09c DataFrame\uc774\ub098 RDD\ub97c \uba54\ubaa8\ub9ac\ub098 \ub514\uc2a4\ud06c\uc5d0 \uc784\uc2dc\ub85c \uc800\uc7a5\ud574 \ub450\ub294 \uae30\ubc95\uc774\ub2e4. \uac00\uc7a5 \ud070 \ud2b9\uc9d5\uc740 **\ub370\uc774\ud130\uc758 \uacc4\uc0b0 \uc871\ubcf4(Lineage)\ub97c \uadf8\ub300\ub85c \uc720\uc9c0**\ud55c\ub2e4\ub294 \uc810\uc774\ub2e4. \uc989, \uce90\uc2dc\ub41c \ub370\uc774\ud130\uac00 \ub0a0\uc544\uac00\uba74 \uc2a4\ud30c\ud06c\ub294 \uc5b8\uc81c\ub4e0 \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uacc4\uc0b0\ud574\uc11c \ubcf5\uad6c\ud560 \uc218 \uc788\ub2e4.\\n\\n### 1-1. DataFrame \uce90\uc2f1\uacfc StorageLevel\\n\uc2a4\ud30c\ud06c\ub294 \uc0c1\ud669\uc5d0 \ub9de\uac8c \ub370\uc774\ud130\ub97c \uc5b4\ub514\uc5d0, \uc5b4\ub5bb\uac8c \uc800\uc7a5\ud560\uc9c0 \uacb0\uc815\ud558\ub294 \ub2e4\uc591\ud55c `StorageLevel`\uc744 \uc81c\uacf5\ud55c\ub2e4.\\n\\n```scala\\nimport org.apache.spark.sql.SparkSession\\nimport org.apache.spark.storage.StorageLevel\\n\\nval spark = SparkSession.builder()\\n  .appName(\\"CachingDemo\\")\\n  .config(\\"spark.memory.offHeap.enabled\\", \\"true\\")\\n  .config(\\"spark.memory.offHeap.size\\", 10000000)\\n  .master(\\"local\\")\\n  .getOrCreate()\\n\\nval flightsDF = spark.read.option(\\"inferSchema\\", \\"true\\").json(\\"src/main/resources/data/flights\\")\\nval orderedFlightsDF = flightsDF.orderBy(\\"dist\\") // \ubb34\uac70\uc6b4 \uc5f0\uc0b0 \uac00\uc815\\n\\n// \ub2e4\uc591\ud55c \uce90\uc2f1 \uc635\uc158 \uc801\uc6a9\\norderedFlightsDF.persist(\\n  // 1. \uba54\ubaa8\ub9ac\uc5d0 \uc6d0\ubcf8 \uac1d\uccb4\ub85c \uc800\uc7a5 (\uac00\uc7a5 \ube60\ub984, OOM \uc704\ud5d8)\\n  // StorageLevel.MEMORY_ONLY \\n  \\n  // 2. \ub514\uc2a4\ud06c\uc5d0\ub9cc \uc800\uc7a5 (\uba54\ubaa8\ub9ac \uc808\uc57d, I/O\ub85c \uc778\ud574 \ub290\ub9bc)\\n  // StorageLevel.DISK_ONLY \\n  \\n  // 3. \uba54\ubaa8\ub9ac\uc5d0 \uba3c\uc800 \ucc44\uc6b0\uace0, \ub118\uce58\uba74 \ub514\uc2a4\ud06c\ub85c Spill (DF \uae30\ubcf8\uac12)\\n  // StorageLevel.MEMORY_AND_DISK \\n\\n  // 4. \uac00\ube44\uc9c0 \uceec\ub809\ud130(GC)\ub97c \ud68c\ud53c\ud558\ub294 Off-Heap \uba54\ubaa8\ub9ac \uc800\uc7a5 (Tungsten \uc5d4\uc9c4 \ud65c\uc6a9)\\n  StorageLevel.OFF_HEAP \\n)\\n\\norderedFlightsDF.count() // \uccab \ubc88\uc9f8 \uc561\uc158: \uacc4\uc0b0 \ud6c4 \uce90\uc2dc \uba54\ubaa8\ub9ac\uc5d0 \uc801\uc7ac\ub428\\norderedFlightsDF.count() // \ub450 \ubc88\uc9f8 \uc561\uc158: \uce90\uc2dc\uc5d0\uc11c \ubc14\ub85c \uc77d\uc5b4\uc640\uc11c \ud6e8\uc52c \ube60\ub984!\\n\\n// \uce90\uc2dc \uba54\ubaa8\ub9ac \ud574\uc81c\\norderedFlightsDF.unpersist()\\n```\\n\\n### 1-2. RDD \uc9c1\ub82c\ud654 \uce90\uc2f1 (\uba54\ubaa8\ub9ac \ub2e4\uc774\uc5b4\ud2b8)\\n\uc624\ub798\ub41c RDD API\ub97c \uc0ac\uc6a9\ud560 \ub54c\ub294 `_SER`(Serialized) \uc635\uc158\uc774 \ud544\uc218\uc801\uc774\ub2e4.\\n\\n```scala\\nval flightsRDD = orderedFlightsDF.rdd\\n\\n// \uc790\ubc14 \uac1d\uccb4 \ub300\uc2e0 \ubc14\uc774\ud2b8 \ubc30\uc5f4\ub85c \uc9c1\ub82c\ud654\ud558\uc5ec \uba54\ubaa8\ub9ac \uc6a9\ub7c9 \uadf9\uc801 \uc808\uac10\\nflightsRDD.persist(StorageLevel.MEMORY_ONLY_SER)\\nflightsRDD.count()\\n```\\nRDD\ub294 \ubb34\uac70\uc6b4 JVM \uac1d\uccb4\ub97c \uc0dd\uc131\ud558\uae30 \ub54c\ubb38\uc5d0 `MEMORY_ONLY`\ub97c \uc4f0\uba74 OOM\uc774 \ud130\uc9c0\uae30 \uc27d\ub2e4. \ud558\uc9c0\ub9cc DataFrame\uc744 \uc4f0\uba74 \uc2a4\ud30c\ud06c \uce74\ud0c8\ub9ac\uc2a4\ud2b8(Catalyst) \uc5d4\uc9c4\uc774 \uc54c\uc544\uc11c \ud6a8\uc728\uc801\uc778 \ubc14\uc774\ub108\ub9ac \ud3ec\ub9f7\uc73c\ub85c \uc800\uc7a5\ud574\uc8fc\uae30 \ub54c\ubb38\uc5d0 \uad73\uc774 RDD\ub85c \ubcc0\ud658\ud574\uc11c \uce90\uc2f1\ud560 \ud544\uc694\ub294 \uc5c6\ub2e4.\\n\\n---\\n\\n## 2. Checkpointing: DAG\ub97c \ub04a\uc5b4\ub0b4\ub294 \ub2e8\ub450\ub300\\n\\n\uccb4\ud06c\ud3ec\uc778\ud305\uc740 \uba54\ubaa8\ub9ac \ubd80\uc871\uc774\ub098 \ub178\ub4dc \uc7a5\uc560\ub97c \ub300\ube44\ud574, \ub370\uc774\ud130\ub97c \uc784\uc2dc\uac00 \uc544\ub2cc **HDFS\ub098 \ub85c\uceec \ub514\uc2a4\ud06c \uac19\uc740 \uc601\uad6c\uc801\uc774\uace0 \uc548\uc804\ud55c \uc800\uc7a5\uc18c\uc5d0 \ubb3c\ub9ac\uc801\uc73c\ub85c \uae30\ub85d**\ud574 \ubc84\ub9ac\ub294 \uae30\ubc95\uc774\ub2e4. \\n\\n\uac00\uc7a5 \uc911\uc694\ud55c \ucc28\uc774\ub294 **\uacc4\uc0b0 \uc871\ubcf4(Lineage, DAG)\ub97c \uc2f9\ub451 \ub04a\uc5b4\ubc84\ub9b0\ub2e4**\ub294 \uac83\uc774\ub2e4.\\n\\n\\n\\n### 2-1. Checkpointing \ucf54\ub4dc \uad6c\ud604\\n\uccb4\ud06c\ud3ec\uc778\ud305\uc744 \uc0ac\uc6a9\ud558\ub824\uba74 \ubc18\ub4dc\uc2dc \uc2a4\ud30c\ud06c \ucee8\ud14d\uc2a4\ud2b8(`sc`)\uc5d0 \uc800\uc7a5\ud560 \ub514\ub809\ud1a0\ub9ac\ub97c \uba3c\uc800 \uc9c0\uc815\ud574\uc57c \ud55c\ub2e4.\\n\\n```scala\\nval sc = spark.sparkContext\\n// \uccb4\ud06c\ud3ec\uc778\ud2b8 \uc800\uc7a5 \uacbd\ub85c \uc124\uc815 (\uc2e4\ubb34\uc5d0\uc11c\ub294 HDFS\ub098 S3 \uacbd\ub85c \uc0ac\uc6a9)\\nsc.setCheckpointDir(\\"spark-warehouse\\")\\n\\nval orderedFlights = flightsDF.orderBy(\\"dist\\")\\n\\n// checkpoint() \uc790\uccb4\uac00 \uc561\uc158(Action)\uc744 \ud2b8\ub9ac\uac70\ud558\uba70 \ub514\uc2a4\ud06c\uc5d0 \ub370\uc774\ud130\ub97c \uc4f4\ub2e4.\\nval checkpointedFlights = orderedFlights.checkpoint() \\n\\ncheckpointedFlights.count() // \ub514\uc2a4\ud06c\uc5d0\uc11c \ubc14\ub85c \uc77d\uc5b4\uc634\\n```\\n\\n### 2-2. \uc2e4\ud589 \uacc4\ud68d(Physical Plan) \ube44\uad50 \ubd84\uc11d\\n\uce90\uc2f1\uacfc \uccb4\ud06c\ud3ec\uc778\ud305\uc758 \uadfc\ubcf8\uc801\uc778 \ucc28\uc774\ub294 `explain()`\uc744 \ud1b5\ud574 \uc2e4\ud589 \uacc4\ud68d\uc744 \uc5f4\uc5b4\ubd24\uc744 \ub54c \uba85\ud655\ud558\uac8c \ub4dc\ub7ec\ub09c\ub2e4.\\n\\n**[\uc77c\ubc18 DF \ub610\ub294 \uce90\uc2f1\ub41c DF\uc758 \uc2e4\ud589 \uacc4\ud68d]**\\n```text\\norderedFlights.explain()\\n/*\\n== Physical Plan ==\\n*(1) Sort [dist#16 ASC NULLS FIRST], true, 0\\n+- *(1) Project [_id#7, arrdelay#8, ... ]\\n   +- BatchScan[...] JsonScan Location: InMemoryFileIndex[...]\\n*/\\n```\\n\uc704\ucc98\ub7fc \uce90\uc2dc\ub97c \uc4f0\ub354\ub77c\ub3c4 \uc2a4\ud30c\ud06c\ub294 \\"\uc5ec\ucc28\ud558\uba74 \ub0b4\uac00 \ud30c\uc77c\ubd80\ud130 \ub2e4\uc2dc \uc77d\uc5b4\uc11c Sort\ud560\uac8c\\"\ub77c\uba70 \uc804\uccb4 \uacc4\ud68d(Lineage)\uc744 \uae38\uac8c \ub4e4\uace0 \uc788\ub2e4.\\n\\n**[\uccb4\ud06c\ud3ec\uc778\ud2b8\ub41c DF\uc758 \uc2e4\ud589 \uacc4\ud68d]**\\n```text\\ncheckpointedFlights.explain()\\n/*\\n== Physical Plan ==\\n*(1) Scan ExistingRDD[_id#7,arrdelay#8, ... ]\\n*/\\n```\\n\uccb4\ud06c\ud3ec\uc778\ud2b8 \uc774\ud6c4\uc758 \ub370\uc774\ud130\ud504\ub808\uc784\uc740 \uc774\uc804\uc758 `Sort`, `Project`, `JsonScan` \uac19\uc740 \ubcf5\uc7a1\ud55c \uacfc\uac70\ub97c \uc644\uc804\ud788 \uc78a\uc5b4\ubc84\ub9b0\ub2e4. \uc624\uc9c1 \ub514\uc2a4\ud06c\uc5d0 \uc800\uc7a5\ub41c \uacb0\uacfc\ubb3c(`ExistingRDD`)\uc744 \uc0c8\ub85c\uc6b4 \uc2dc\uc791\uc810(Source)\uc73c\ub85c \uc0bc\ub294\ub2e4.\\n\\n---\\n\\n## 3. \uc694\uc57d \ubc0f \uc2e4\uc804 \uacb0\ub860: \uc5b8\uc81c \ubb34\uc5c7\uc744 \uc368\uc57c \ud560\uae4c?\\n\\n| \uad6c\ubd84 | Caching (\uce90\uc2f1) | Checkpointing (\uccb4\ud06c\ud3ec\uc778\ud305) |\\n| :--- | :--- | :--- |\\n| **\uc800\uc7a5 \uc704\uce58** | \uba54\ubaa8\ub9ac \uc911\uc2ec (\uc124\uc815\uc5d0 \ub530\ub77c \ub514\uc2a4\ud06c \ud63c\uc6a9) | \uc601\uad6c \uc800\uc7a5\uc18c (HDFS, S3, \ub85c\uceec \ub514\uc2a4\ud06c \ub4f1) |\\n| **Lineage (\uc871\ubcf4)** | \uc720\uc9c0\ub428 (\uc7a5\uc560 \uc2dc \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \uacc4\uc0b0) | **\ub2e8\uc808\ub428** (\uacfc\uac70 \uc5f0\uc0b0 \uae30\ub85d \uc0ad\uc81c) |\\n| **\uc18d\ub3c4** | \ub9e4\uc6b0 \ube60\ub984 (\ud2b9\ud788 \uba54\ubaa8\ub9ac Hit \uc2dc) | \uc0c1\ub300\uc801\uc73c\ub85c \ub290\ub9bc (\ub514\uc2a4\ud06c I/O \ubc1c\uc0dd) |\\n| **\ubaa9\uc801** | \ubc18\ubcf5 \uc5f0\uc0b0 \uc18d\ub3c4 \ud5a5\uc0c1 | \uc7a5\uc560 \ubcf5\uad6c, \uae34 \uc5f0\uc0b0 \uccb4\uc778 \ub04a\uae30 |\\n\\n### \ud83d\ude80 Caching\uc744 \uc368\uc57c \ud560 \ub54c (Performance Focus)\\n* \ub3d9\uc77c\ud55c \uc7a1(Job) \uc548\uc5d0\uc11c \uba38\uc2e0\ub7ec\ub2dd \ubaa8\ub378\uc744 \ubc18\ubcf5 \ud559\uc2b5\uc2dc\ud0ac \ub54c.\\n* \ub8e9\uc5c5 \ud14c\uc774\ube14(Lookup Table)\ucc98\ub7fc \uc790\uc8fc \uc870\uc778\ub418\ub294 \uc791\uc740 DataFrame\uc744 \uc7ac\uc0ac\uc6a9\ud560 \ub54c.\\n* \uc5f0\uc0b0 \uc18d\ub3c4\ub97c \uc950\uc5b4\uc9dc\uc57c \ud558\ub294 \uc0c1\ud669\uc77c \ub54c.\\n\\n### \ud83d\udee1\ufe0f Checkpointing\uc744 \uc368\uc57c \ud560 \ub54c (Reliability Focus)\\n* **\ubc30\uce58 \uc791\uc5c5 \uc2dc\uac04\uc774 \ub108\ubb34 \uae38\uc5b4\uc11c** \uc911\uac04\uc5d0 \uc5d0\ub7ec\uac00 \ub0ac\uc744 \ub54c \ucc98\uc74c\ubd80\ud130 \ub2e4\uc2dc \ub3cc\ub9ac\ub294 \uac83\uc774 \uc7ac\uc559\uc778 \uacbd\uc6b0.\\n* DataFrame\uc758 `withColumn`\uc774\ub098 `join` \ubcc0\ud658\uc774 \uc218\uc2ed, \uc218\ubc31 \ubc88 \uacb9\uccd0\uc11c **\uc2e4\ud589 \uacc4\ud68d(DAG)\uc774 \ub108\ubb34 \uae38\uc5b4\uc9c0\uace0 \uba54\ubaa8\ub9ac\ub97c \ub9ce\uc774 \uba39\uc5b4 \ub4dc\ub77c\uc774\ubc84\uc5d0\uc11c `StackOverflowError`\uac00 \ud130\uc9c8 \uc704\ud5d8**\uc774 \uc788\uc744 \ub54c. (\uc774\ub54c \uccb4\ud06c\ud3ec\uc778\ud2b8\ub97c \ud55c \ubc88\uc529 \ucc0d\uc5b4\uc8fc\uba74 DAG\uac00 \ucd08\uae30\ud654\ub418\uc5b4 \uc5d0\ub7ec\ub97c \ub9c9\uc744 \uc218 \uc788\ub2e4.)\\n* Spark Structured Streaming \uc6b4\uc601 \uc2dc \uc7a5\uc560 \ubcf5\uad6c\ub97c \uc704\ud574.\\n\\n### \ud83d\udca1 \uc2e4\ubb34 \uc6b4\uc601 \ud301\\n\ud604\uc5c5\uc5d0\uc11c\ub294 \uae34 \ub370\uc774\ud130 \ud30c\uc774\ud504\ub77c\uc778\uc744 \uc124\uacc4\ud560 \ub54c, \uc911\uac04\uc911\uac04 \ubb34\uac70\uc6b4 \uc154\ud50c(Shuffle)\uc774 \ub05d\ub098\ub294 \uc9c0\uc810\uc5d0 **\uce90\uc2f1\uacfc \uccb4\ud06c\ud3ec\uc778\ud305\uc744 \ud568\uaed8 \uc0ac\uc6a9**\ud558\uae30\ub3c4 \ud55c\ub2e4. \ub370\uc774\ud130\ub97c \uba54\ubaa8\ub9ac\uc5d0 \uc62c\ub824 \ube60\ub974\uac8c \uc7ac\uc0ac\uc6a9\ud558\uba74\uc11c\ub3c4, \ub514\uc2a4\ud06c\uc5d0 \uc548\uc804\ud558\uac8c \ubc31\uc5c5\ud574\ub450\uc5b4 DAG\ub97c \uc790\ub974\uace0 \uc7a5\uc560\uc5d0 \ub300\ube44\ud558\ub294 \ud6cc\ub96d\ud55c \uc804\ub7b5\uc774\ub2e4."},{"id":"first-test","metadata":{"permalink":"/spark-study/blog/first-test","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-02-19-first-test.md","source":"@site/blog/2026-02-19-first-test.md","title":"1\uc8fc\ucc28: Spark DataFrame OOM \ud14c\uc2a4\ud2b8 \ubc0f \ud658\uacbd \uc138\ud305","description":"\uccab \ubc88\uc9f8 \uc2a4\ud130\ub514 \ud14c\uc2a4\ud2b8 \uae00\uc785\ub2c8\ub2e4. \uc774\ubc88 \uc8fc\ucc28\uc5d0\uc11c\ub294 Data Skew\ub85c \uc778\ud55c \uba54\ubaa8\ub9ac \ucd08\uacfc \ud604\uc0c1\uc744 \uc7ac\ud604\ud569\ub2c8\ub2e4.","date":"2026-02-19T00:00:00.000Z","tags":[{"inline":true,"label":"spark","permalink":"/spark-study/blog/tags/spark"},{"inline":true,"label":"scala","permalink":"/spark-study/blog/tags/scala"},{"inline":true,"label":"troubleshooting","permalink":"/spark-study/blog/tags/troubleshooting"}],"readingTime":0.37,"hasTruncateMarker":false,"authors":[{"name":"Kwon Younglin","title":"Data Engineer","url":"https://github.com/kwonyl14","imageURL":"https://github.com/kwonyl14.png","key":"kwonyl14","page":null}],"frontMatter":{"slug":"first-test","title":"1\uc8fc\ucc28: Spark DataFrame OOM \ud14c\uc2a4\ud2b8 \ubc0f \ud658\uacbd \uc138\ud305","authors":"kwonyl14","tags":["spark","scala","troubleshooting"]},"unlisted":false,"prevItem":{"title":"1\uc8fc\ucc28: Spark Caching\uacfc Checkpointing\uc758 \ucc28\uc774\uc640 \uc2e4\uc804 \ud65c\uc6a9\ubc95","permalink":"/spark-study/blog/week-1-caching-vs-checkpointing"}},"content":"\uccab \ubc88\uc9f8 \uc2a4\ud130\ub514 \ud14c\uc2a4\ud2b8 \uae00\uc785\ub2c8\ub2e4. \uc774\ubc88 \uc8fc\ucc28\uc5d0\uc11c\ub294 Data Skew\ub85c \uc778\ud55c \uba54\ubaa8\ub9ac \ucd08\uacfc \ud604\uc0c1\uc744 \uc7ac\ud604\ud569\ub2c8\ub2e4.\\n\\n### OOM \uc7ac\ud604\uc744 \uc704\ud55c Scala \ud14c\uc2a4\ud2b8 \ucf54\ub4dc\\n\\n```scala\\nimport org.apache.spark.sql.SparkSession\\nimport org.apache.spark.sql.functions._\\n\\nval spark = SparkSession.builder()\\n  .appName(\\"SkewTest\\")\\n  .config(\\"spark.memory.fraction\\", \\"0.2\\") // \uba54\ubaa8\ub9ac \uc555\ubc15\uc744 \uc704\ud574 \ub0ae\uac8c \uc124\uc815\\n  .getOrCreate()\\n\\nimport spark.implicits._\\n\\n// \uace0\uc758\uc801\uc778 Data Skew \uc0dd\uc131\\nval df1 = Seq.fill(100000)(\\"A\\").toDF(\\"key\\") \\nval df2 = Seq(\\"A\\", \\"B\\", \\"C\\").toDF(\\"key\\")\\n\\n// \uc2e4\ud589 \uc2dc Shuffle \ubcd1\ubaa9 \ubc1c\uc0dd \uc720\ub3c4\\nval joinedDF = df1.join(df2, \\"key\\")\\njoinedDF.show()"}]}}')}}]);